html:
{% set co = get_company_info(doc.company) %}
{% set co_addr = get_company_address(doc.company) %}

<style>
* { margin: 0; padding: 0; box-sizing: border-box; }
body {
  font-family: 'Inter', Arial, sans-serif;
  font-size: 11px;
  color: #1a1a1a;
  background: white;
  padding: 8px;
}
.ol-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  padding-bottom: 18px;
  border-bottom: 3px solid #0F2340;
  margin-bottom: 22px;
}
.ol-company-name {
  font-size: 20px;
  font-weight: 800;
  color: #0F2340;
  letter-spacing: 1.5px;
  text-transform: uppercase;
}
.ol-company-meta {
  font-size: 9.5px;
  color: #555;
  margin-top: 6px;
  line-height: 1.7;
}
.ol-doc-block { text-align: right; min-width: 210px; }
.ol-doc-type {
  font-size: 16px;
  font-weight: 800;
  color: #7C3AED;
  text-transform: uppercase;
  letter-spacing: 2px;
}
.ol-doc-number {
  font-size: 12px;
  font-weight: 700;
  color: #0F2340;
  margin-top: 5px;
}
.ol-doc-meta {
  font-size: 9.5px;
  color: #555;
  margin-top: 5px;
  line-height: 1.8;
}
.ol-doc-meta b { color: #0F2340; }
.ol-due-badge {
  display: inline-block;
  background: #7C3AED;
  color: #fff;
  font-size: 9px;
  font-weight: 700;
  padding: 3px 8px;
  border-radius: 3px;
  margin-top: 6px;
  letter-spacing: 0.5px;
}
.ol-section-label {
  font-size: 8.5px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.2px;
  color: #7C3AED;
  margin-bottom: 6px;
}
.ol-two-col {
  display: flex;
  gap: 24px;
  margin-bottom: 22px;
}
.ol-box {
  flex: 1;
  background: #f6f8fd;
  border-left: 3px solid #0F2340;
  padding: 10px 14px;
}
.ol-box-title {
  font-size: 8px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #7C3AED;
  margin-bottom: 5px;
}
.ol-box-name { font-size: 12px; font-weight: 700; color: #0F2340; }
.ol-box-meta { font-size: 9.5px; color: #555; margin-top: 3px; line-height: 1.6; }
table.ol-items {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 16px;
  font-size: 10.5px;
}
table.ol-items thead tr { background: #0F2340; color: #fff; }
table.ol-items thead th {
  padding: 8px 10px;
  font-size: 9.5px;
  font-weight: 600;
  letter-spacing: 0.4px;
}
table.ol-items tbody tr { border-bottom: 1px solid #e4e8f0; }
table.ol-items tbody tr:nth-child(even) { background: #f5f3ff; }
table.ol-items tbody td { padding: 7px 10px; vertical-align: top; }
.ol-totals-wrap { display: flex; justify-content: flex-end; margin-bottom: 20px; }
.ol-totals { width: 280px; }
.ol-totals table { width: 100%; border-collapse: collapse; }
.ol-totals td { padding: 5px 8px; font-size: 10.5px; }
.ol-totals .lbl { color: #555; }
.ol-totals .val { text-align: right; font-weight: 600; }
.ol-totals .sep { border-top: 1px solid #ddd; }
.ol-total-row { background: #0F2340; color: #fff; }
.ol-total-row td { padding: 9px 10px; font-size: 13px; font-weight: 700; }
.ol-total-row .val { text-align: right; }
.ol-payment-section {
  background: #f5f3ff;
  border: 1px solid #ddd8fe;
  border-radius: 4px;
  padding: 12px 16px;
  margin-bottom: 20px;
}
.ol-payment-title {
  font-size: 9px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1px;
  color: #7C3AED;
  margin-bottom: 8px;
}
.ol-payment-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4px 20px;
  font-size: 9.5px;
}
.ol-payment-grid .lbl { color: #555; }
.ol-payment-grid .val { color: #0F2340; font-weight: 600; }
.ol-legal {
  font-size: 8.5px;
  color: #999;
  border-top: 1px solid #ddd;
  padding-top: 10px;
  margin-top: 10px;
  line-height: 1.6;
}
.ol-footer {
  display: flex;
  justify-content: space-between;
  margin-top: 16px;
  padding-top: 10px;
  border-top: 1px solid #ddd;
  font-size: 9px;
  color: #888;
}
.tr { text-align: right; }
.tc { text-align: center; }
</style>

<!-- HEADER -->
<div class="ol-header">
  <div>
    <div class="ol-company-name">{{ doc.company }}</div>
    <div class="ol-company-meta">
      {%- if co_addr %}{{ co_addr }}<br>{% endif %}
      {%- if co.phone %}{{ _("Tél") }}: {{ co.phone }}<br>{% endif %}
      {%- if co.email %}{{ co.email }}<br>{% endif %}
      {%- if co.tax_id %}{{ _("ICE") }} : {{ co.tax_id }}{% endif %}
    </div>
  </div>
  <div class="ol-doc-block">
    {%- if doc.is_return %}
    <div class="ol-doc-type">{{ _("Avoir") }}</div>
    {%- else %}
    <div class="ol-doc-type">{{ _("Facture") }}</div>
    {%- endif %}
    <div class="ol-doc-number">{{ doc.name }}</div>
    <div class="ol-doc-meta">
      {{ _("Date") }} : <b>{{ frappe.format_date(doc.posting_date) }}</b><br>
      {%- if doc.due_date %}
      {{ _("Échéance") }} : <b>{{ frappe.format_date(doc.due_date) }}</b>
      {%- endif %}
    </div>
    {%- if doc.due_date %}
    <div class="ol-due-badge">{{ _("DÛ LE") }} {{ frappe.format_date(doc.due_date) }}</div>
    {%- endif %}
  </div>
</div>

<!-- BILL TO + SHIP TO -->
<div class="ol-two-col">
  <div class="ol-box">
    <div class="ol-box-title">{{ _("Facturé à") }}</div>
    <div class="ol-box-name">{{ doc.customer_name }}</div>
    {%- if doc.address_display %}
    <div class="ol-box-meta">{{ doc.address_display | striptags | replace('\n', ', ') }}</div>
    {%- endif %}
    {%- if doc.contact_display %}
    <div class="ol-box-meta">{{ _("Contact") }} : {{ doc.contact_display }}</div>
    {%- endif %}
    {%- if doc.customer_gstin %}
    <div class="ol-box-meta">{{ _("ICE client") }} : {{ doc.customer_gstin }}</div>
    {%- endif %}
  </div>
  <div class="ol-box">
    <div class="ol-box-title">{{ _("Références") }}</div>
    <div class="ol-box-meta">
      {%- if doc.po_no %}
      {{ _("Bon de commande") }} : <b>{{ doc.po_no }}</b><br>
      {%- endif %}
      {%- for item in doc.items if item.sales_order %}
      {%- if loop.first %}
      {{ _("Commande") }} : <b>{{ item.sales_order }}</b><br>
      {%- endif %}
      {%- endfor %}
      {%- for item in doc.items if item.delivery_note %}
      {%- if loop.first %}
      {{ _("Livraison") }} : <b>{{ item.delivery_note }}</b><br>
      {%- endif %}
      {%- endfor %}
      {%- if doc.payment_terms_template %}
      {{ _("Conditions") }} : <b>{{ doc.payment_terms_template }}</b>
      {%- endif %}
    </div>
  </div>
</div>

<!-- ITEMS -->
<div class="ol-section-label">{{ _("Détail de la facture") }}</div>
<table class="ol-items">
  <thead>
    <tr>
      <th class="tc" style="width:28px">#</th>
      <th style="width:110px">{{ _("Référence") }}</th>
      <th>{{ _("Désignation") }}</th>
      <th class="tc" style="width:48px">{{ _("Qté") }}</th>
      <th class="tc" style="width:38px">{{ _("U.") }}</th>
      <th class="tr" style="width:96px">{{ _("Prix Unit. HT") }}</th>
      <th class="tr" style="width:96px">{{ _("Montant HT") }}</th>
    </tr>
  </thead>
  <tbody>
    {%- for item in doc.items %}
    <tr>
      <td class="tc">{{ loop.index }}</td>
      <td>{{ item.item_code }}</td>
      <td>
        {{ item.item_name }}
        {%- if item.description and item.description != item.item_name %}
        <div style="font-size:9px;color:#777;margin-top:2px">{{ item.description | striptags }}</div>
        {%- endif %}
      </td>
      <td class="tc">{{ item.qty | int if item.qty == (item.qty | int) else item.qty }}</td>
      <td class="tc">{{ item.uom }}</td>
      <td class="tr">{{ format_currency_fr(item.rate, doc.currency) }}</td>
      <td class="tr">{{ format_currency_fr(item.amount, doc.currency) }}</td>
    </tr>
    {%- endfor %}
  </tbody>
</table>

<!-- TOTALS -->
<div class="ol-totals-wrap">
  <div class="ol-totals">
    <table>
      <tr>
        <td class="lbl">{{ _("Sous-total HT") }}</td>
        <td class="val">{{ format_currency_fr(doc.net_total, doc.currency) }}</td>
      </tr>
      {%- for tax in doc.taxes %}
      <tr>
        <td class="lbl">{{ tax.description }}</td>
        <td class="val">{{ format_currency_fr(tax.tax_amount, doc.currency) }}</td>
      </tr>
      {%- endfor %}
      {%- if doc.discount_amount %}
      <tr>
        <td class="lbl">{{ _("Remise") }}</td>
        <td class="val">- {{ format_currency_fr(doc.discount_amount, doc.currency) }}</td>
      </tr>
      {%- endif %}
      <tr class="sep"><td colspan="2"></td></tr>
      <tr class="ol-total-row">
        <td>{{ _("TOTAL TTC") }}</td>
        <td class="val">{{ format_currency_fr(doc.grand_total, doc.currency) }}</td>
      </tr>
      {%- if doc.outstanding_amount %}
      <tr>
        <td class="lbl" style="padding-top:8px">{{ _("Déjà réglé") }}</td>
        <td class="val" style="padding-top:8px">{{ format_currency_fr(doc.grand_total - doc.outstanding_amount, doc.currency) }}</td>
      </tr>
      <tr>
        <td class="lbl"><b>{{ _("Reste à payer") }}</b></td>
        <td class="val"><b>{{ format_currency_fr(doc.outstanding_amount, doc.currency) }}</b></td>
      </tr>
      {%- endif %}
    </table>
  </div>
</div>

<!-- PAYMENT INSTRUCTIONS -->
<div class="ol-payment-section">
  <div class="ol-payment-title">{{ _("Instructions de paiement") }}</div>
  <div class="ol-payment-grid">
    <span class="lbl">{{ _("Bénéficiaire") }}</span>
    <span class="val">{{ doc.company }}</span>
    {%- if co.bank %}
    <span class="lbl">{{ _("Banque") }}</span>
    <span class="val">{{ co.bank }}</span>
    {%- endif %}
    {%- if co.iban %}
    <span class="lbl">IBAN</span>
    <span class="val">{{ co.iban }}</span>
    {%- endif %}
    <span class="lbl">{{ _("Réf. à mentionner") }}</span>
    <span class="val">{{ doc.name }}</span>
  </div>
</div>

<!-- LEGAL -->
<div class="ol-legal">
  {{ _("Tout retard de paiement entraîne des pénalités de retard au taux légal en vigueur.") }}
  {%- if co.tax_id %} · {{ _("ICE") }} : {{ co.tax_id }}{%- endif %}
</div>

<!-- FOOTER -->
<div class="ol-footer">
  <div><b>{{ doc.company }}</b>{%- if co_addr %} · {{ co_addr }}{% endif %}</div>
  <div>{{ doc.name }} · {{ frappe.format_date(doc.posting_date) }}</div>
</div>
